// Build the OVH SMS API call (URL + signed headers + JSON body).
// OVH signature scheme:
//   X-Ovh-Signature = '$1$' + sha1(AS + '+' + CK + '+' + METHOD + '+' + URL + '+' + BODY + '+' + TIMESTAMP)
// The timestamp uses local epoch seconds (close enough to OVH server time for most setups).
// If you get INVALID_SIGNATURE errors, replace it by a GET /auth/time call.

const crypto = require('crypto');
const creds = $('Set OVH API Credentials').item.json;
const payload = $('Prepare SMS Payload').item.json;

const AK = creds.APPLICATION_KEY;
const AS = creds.APPLICATION_SECRET;
const CK = creds.CONSUMER_KEY;
const service = creds.SMS_SERVICE_NAME;
const sender = creds.SMS_SENDER || 'n8n';
const host = (creds.OVH_REGION === 'ca') ? 'https://ca.api.ovh.com/1.0' : 'https://eu.api.ovh.com/1.0';

if (!AK || !AS || !CK || !service) {
  throw new Error('Missing OVH credentials (APPLICATION_KEY / APPLICATION_SECRET / CONSUMER_KEY / SMS_SERVICE_NAME).');
}

const url = `${host}/sms/${service}/jobs`;
const body = {
  message: payload.message,
  receivers: [payload.receiver],
  sender: sender,
  senderForResponse: false,
  charset: 'UTF-8',
  class: 'phoneDisplay',
  noStopClause: true
};
const bodyString = JSON.stringify(body);
const timestamp = Math.floor(Date.now() / 1000);
const toSign = [AS, CK, 'POST', url, bodyString, timestamp].join('+');
const signature = '$1$' + crypto.createHash('sha1').update(toSign).digest('hex');

return [{
  json: {
    url,
    body,
    headers: {
      'X-Ovh-Application': AK,
      'X-Ovh-Consumer': CK,
      'X-Ovh-Timestamp': timestamp.toString(),
      'X-Ovh-Signature': signature,
      'Content-Type': 'application/json'
    }
  }
}];
